#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#define MAX_N 100005
#define MAX_E 200005
#define INF LLONG_MAX

// Define the structure for an edge
typedef struct {
    int u, v, w;
} Edge;

// Define the structure for the Union-Find data structure
typedef struct {
    int parent[MAX_N], rank[MAX_N];
} UnionFind;

// Function to initialize the Union-Find data structure
void init(UnionFind *uf, int n) {
    for (int i = 0; i < n; i++) {
        uf->parent[i] = i;
        uf->rank[i] = 0;
    }
}

// Function to find the root of a set
int find(UnionFind *uf, int x) {
    if (uf->parent[x] != x) {
        uf->parent[x] = find(uf, uf->parent[x]);
    }
    return uf->parent[x];
}

// Function to union two sets
void unionSet(UnionFind *uf, int x, int y) {
    int rootX = find(uf, x);
    int rootY = find(uf, y);
    if (rootX != rootY) {
        if (uf->rank[rootX] < uf->rank[rootY]) {
            uf->parent[rootX] = rootY;
        } else if (uf->rank[rootX] > uf->rank[rootY]) {
            uf->parent[rootY] = rootX;
        } else {
            uf->parent[rootY] = rootX;
            uf->rank[rootX]++;
        }
    }
}

// Function to find the minimum spanning tree using Kruskal's algorithm
long long kruskal(Edge *edges, int n, int m) {
    UnionFind uf;
    init(&uf, n);
    long long totalWeight = 0;
    int edgeCount = 0;
    for (int i = 0; i < m; i++) {
        int u = edges[i].u;
        int v = edges[i].v;
        int w = edges[i].w;
        if (find(&uf, u) != find(&uf, v)) {
            unionSet(&uf, u, v);
            totalWeight += w;
            edgeCount++;
        }
    }
    if (edgeCount != n - 1) {
        return -1;
    }
    return totalWeight;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        Edge edges[m];
        for (int i = 0; i < m; i++) {
            scanf("%d %d %d", &edges[i].u, &edges[i].v, &edges[i].w);
        }
        // Sort the edges in non-decreasing order of their weights
        qsort(edges, m, sizeof(Edge), (int (*)(const void *, const void *))compareEdges);
        for (int i = 0; i < m; i++) {
            Edge tempEdges[m - 1];
            int tempM = 0;
            for (int j = 0; j < m; j++) {
                if (i != j) {
                    tempEdges[tempM++] = edges[j];
                }
            }
            long long totalWeight = kruskal(tempEdges, n, tempM);
            printf("%lld\n", totalWeight);
        }
    }
    return 0;
}

// Function to compare two edges
int compareEdges(const void *a, const void *b) {
    Edge *edgeA = (Edge *)a;
    Edge *edgeB = (Edge *)b;
    return edgeA->w - edgeB->w;
}

