                parent[rootY] = rootX;
                rank[rootX]++;
            }
        }
    }
};

// Function to find the minimum spanning tree using Kruskal's algorithm
long long kruskal(vector<Edge> &edges, int n) {
    UnionFind uf(n);
    long long totalWeight = 0;
    int edgeCount = 0;
    for (Edge &edge : edges) {
        int u = edge.u;
        int v = edge.v;
        int w = edge.w;
        if (uf.find(u) != uf.find(v)) {
            uf.unionSet(u, v);
            totalWeight += w;
            edgeCount++;
        }
    }
    if (edgeCount != n - 1) {
        return -1;
    }
    return totalWeight;
}

